'use client';

import { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { Card, Input, Button, Select, SelectOption, Modal, ModalHeader, ModalTitle, ModalFooter, Drawer } from '@mmorpg/ui';
import { Search, Filter, MoreVertical, Shield, Ban, CheckCircle, Clock, AlertCircle } from 'lucide-react';
import { LoadingSpinner } from '@/components/loading-spinner';

interface User {
  id: string;
  username: string;
  email: string;
  role: string;
  isBanned: boolean;
  isVerified: boolean;
  lockedUntil: string | null;
  lastLoginAt: string | null;
  createdAt: string;
}

interface UserDetail extends User {
  characters: Array<{
    id: string;
    name: string;
    class: string;
    level: number;
    lastLoginAt: string | null;
  }>;
  recentActivity: Array<{
    id: string;
    actionType: string;
    createdAt: string;
  }>;
  updatedAt: string;
}

export default function UsersPage() {
  const [searchQuery, setSearchQuery] = useState('');
  const [roleFilter, setRoleFilter] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [page, setPage] = useState(1);
  const [selectedUserId, setSelectedUserId] = useState<string | null>(null);
  const [showDetailDrawer, setShowDetailDrawer] = useState(false);
  const [showBanModal, setShowBanModal] = useState(false);
  const [showRoleModal, setShowRoleModal] = useState(false);
  const [banReason, setBanReason] = useState('');
  const [banDuration, setBanDuration] = useState<number | null>(null);
  const [newRole, setNewRole] = useState('');
  const [actionError, setActionError] = useState<string | null>(null);
  const [actionSuccess, setActionSuccess] = useState<string | null>(null);

  const queryClient = useQueryClient();

  const { data: usersData, isLoading } = useQuery({
    queryKey: ['admin', 'users', page, searchQuery, roleFilter, statusFilter],
    queryFn: async () => {
      const params = new URLSearchParams({
        page: page.toString(),
        pageSize: '20',
        ...(searchQuery && { query: searchQuery }),
        ...(roleFilter && { role: roleFilter }),
        ...(statusFilter && { status: statusFilter }),
      });
      const response = await fetch(`/api/admin/users?${params}`);
      if (!response.ok) throw new Error('Failed to fetch users');
      return response.json();
    },
  });

  const { data: userDetail, isLoading: isLoadingDetail } = useQuery({
    queryKey: ['admin', 'users', selectedUserId],
    queryFn: async () => {
      if (!selectedUserId) return null;
      const response = await fetch(`/api/admin/users/${selectedUserId}`);
      if (!response.ok) throw new Error('Failed to fetch user detail');
      return response.json();
    },
    enabled: !!selectedUserId,
  });

  const banUserMutation = useMutation({
    mutationFn: async () => {
      if (!selectedUserId) throw new Error('No user selected');
      const response = await fetch(`/api/admin/users/${selectedUserId}/ban`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          reason: banReason,
          durationHours: banDuration,
        }),
      });
      if (!response.ok) throw new Error('Failed to ban user');
      return response.json();
    },
    onSuccess: () => {
      setActionSuccess('User banned successfully');
      setShowBanModal(false);
      setBanReason('');
      setBanDuration(null);
      queryClient.invalidateQueries({ queryKey: ['admin', 'users'] });
      queryClient.invalidateQueries({ queryKey: ['admin', 'users', selectedUserId] });
      setTimeout(() => setActionSuccess(null), 3000);
    },
    onError: (error) => {
      setActionError(error instanceof Error ? error.message : 'Failed to ban user');
      setTimeout(() => setActionError(null), 3000);
    },
  });

  const unbanUserMutation = useMutation({
    mutationFn: async () => {
      if (!selectedUserId) throw new Error('No user selected');
      const response = await fetch(`/api/admin/users/${selectedUserId}/unban`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
      });
      if (!response.ok) throw new Error('Failed to unban user');
      return response.json();
    },
    onSuccess: () => {
      setActionSuccess('User unbanned successfully');
      queryClient.invalidateQueries({ queryKey: ['admin', 'users'] });
      queryClient.invalidateQueries({ queryKey: ['admin', 'users', selectedUserId] });
      setTimeout(() => setActionSuccess(null), 3000);
    },
    onError: (error) => {
      setActionError(error instanceof Error ? error.message : 'Failed to unban user');
      setTimeout(() => setActionError(null), 3000);
    },
  });

  const changeRoleMutation = useMutation({
    mutationFn: async () => {
      if (!selectedUserId) throw new Error('No user selected');
      const response = await fetch(`/api/admin/users/${selectedUserId}/role`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ role: newRole }),
      });
      if (!response.ok) throw new Error('Failed to change user role');
      return response.json();
    },
    onSuccess: () => {
      setActionSuccess('User role changed successfully');
      setShowRoleModal(false);
      setNewRole('');
      queryClient.invalidateQueries({ queryKey: ['admin', 'users'] });
      queryClient.invalidateQueries({ queryKey: ['admin', 'users', selectedUserId] });
      setTimeout(() => setActionSuccess(null), 3000);
    },
    onError: (error) => {
      setActionError(error instanceof Error ? error.message : 'Failed to change user role');
      setTimeout(() => setActionError(null), 3000);
    },
  });

  const handleViewUser = (userId: string) => {
    setSelectedUserId(userId);
    setShowDetailDrawer(true);
  };

  const handleCloseDrawer = () => {
    setShowDetailDrawer(false);
    setSelectedUserId(null);
  };

  const handleOpenBanModal = () => {
    setShowBanModal(true);
  };

  const handleOpenRoleModal = () => {
    setShowRoleModal(true);
    if (userDetail) {
      setNewRole(userDetail.role);
    }
  };

  return (
    <div className="p-6 space-y-6">
      {/* Header */}
      <div>
        <h1 className="font-heading text-3xl font-bold text-white mb-2">
          User Management
        </h1>
        <p className="text-[#9CA3AF]">
          Search, view, and manage user accounts and permissions.
        </p>
      </div>

      {/* Notifications */}
      {actionSuccess && (
        <div className="bg-green-500/20 border-2 border-green-500/50 rounded-lg p-4 flex items-center gap-3">
          <CheckCircle className="w-5 h-5 text-green-400" />
          <p className="text-green-400 text-sm">{actionSuccess}</p>
        </div>
      )}
      {actionError && (
        <div className="bg-red-500/20 border-2 border-red-500/50 rounded-lg p-4 flex items-center gap-3">
          <AlertCircle className="w-5 h-5 text-red-400" />
          <p className="text-red-400 text-sm">{actionError}</p>
        </div>
      )}

      {/* Search and Filters */}
      <Card className="bg-[#111111] border-2 border-[#7C3AED]/20 p-6">
        <div className="flex flex-col md:flex-row gap-4">
          <div className="flex-1 relative">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-5 h-5 text-[#9CA3AF]" />
            <Input
              placeholder="Search by username or email..."
              value={searchQuery}
              onChange={(e) => {
                setSearchQuery(e.target.value);
                setPage(1);
              }}
              className="pl-10"
            />
          </div>
          <Select
            value={roleFilter}
            onChange={(e) => {
              setRoleFilter(e.target.value);
              setPage(1);
            }}
            className="w-full md:w-40"
          >
            <SelectOption value="">All Roles</SelectOption>
            <SelectOption value="USER">User</SelectOption>
            <SelectOption value="GM">Game Master</SelectOption>
            <SelectOption value="ADMIN">Admin</SelectOption>
          </Select>
          <Select
            value={statusFilter}
            onChange={(e) => {
              setStatusFilter(e.target.value);
              setPage(1);
            }}
            className="w-full md:w-40"
          >
            <SelectOption value="">All Status</SelectOption>
            <SelectOption value="active">Active</SelectOption>
            <SelectOption value="banned">Banned</SelectOption>
            <SelectOption value="verified">Verified</SelectOption>
            <SelectOption value="unverified">Unverified</SelectOption>
          </Select>
        </div>
      </Card>

      {/* Users Table */}
      <Card className="bg-[#111111] border-2 border-[#7C3AED]/20 p-6">
        {isLoading ? (
          <div className="flex items-center justify-center py-12">
            <LoadingSpinner />
          </div>
        ) : (
          <>
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="border-b border-[#7C3AED]/20">
                    <th className="text-left py-3 px-4 text-sm font-semibold text-[#9CA3AF]">
                      Username
                    </th>
                    <th className="text-left py-3 px-4 text-sm font-semibold text-[#9CA3AF]">
                      Email
                    </th>
                    <th className="text-left py-3 px-4 text-sm font-semibold text-[#9CA3AF]">
                      Role
                    </th>
                    <th className="text-left py-3 px-4 text-sm font-semibold text-[#9CA3AF]">
                      Status
                    </th>
                    <th className="text-left py-3 px-4 text-sm font-semibold text-[#9CA3AF]">
                      Joined
                    </th>
                    <th className="text-right py-3 px-4 text-sm font-semibold text-[#9CA3AF]">
                      Actions
                    </th>
                  </tr>
                </thead>
                <tbody>
                  {usersData?.data?.map((user: User) => (
                    <tr
                      key={user.id}
                      className="border-b border-[#7C3AED]/10 hover:bg-[#7C3AED]/5 transition-colors"
                    >
                      <td className="py-3 px-4 text-sm text-white font-medium">
                        {user.username}
                      </td>
                      <td className="py-3 px-4 text-sm text-[#9CA3AF]">
                        {user.email}
                      </td>
                      <td className="py-3 px-4 text-sm">
                        <span className="px-2 py-1 rounded-full text-xs font-semibold bg-[#7C3AED]/20 text-[#7C3AED]">
                          {user.role}
                        </span>
                      </td>
                      <td className="py-3 px-4 text-sm">
                        <div className="flex items-center gap-2">
                          <span
                            className={`px-2 py-1 rounded-full text-xs font-semibold ${
                              user.isBanned
                                ? 'bg-red-500/20 text-red-400'
                                : 'bg-green-500/20 text-green-400'
                            }`}
                          >
                            {user.isBanned ? 'Banned' : 'Active'}
                          </span>
                          {!user.isVerified && (
                            <span className="px-2 py-1 rounded-full text-xs font-semibold bg-yellow-500/20 text-yellow-400">
                              Unverified
                            </span>
                          )}
                        </div>
                      </td>
                      <td className="py-3 px-4 text-sm text-[#9CA3AF]">
                        {new Date(user.createdAt).toLocaleDateString()}
                      </td>
                      <td className="py-3 px-4 text-right">
                        <button
                          onClick={() => handleViewUser(user.id)}
                          className="p-2 hover:bg-[#7C3AED]/10 rounded-lg transition-colors"
                        >
                          <MoreVertical className="w-4 h-4 text-[#9CA3AF]" />
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            {/* Pagination */}
            <div className="mt-6 flex items-center justify-between">
              <p className="text-sm text-[#9CA3AF]">
                Page {usersData?.meta?.page} of {usersData?.meta?.totalPages} (
                {usersData?.meta?.total} total users)
              </p>
              <div className="flex gap-2">
                <Button
                  variant="outline"
                  disabled={!usersData?.meta?.hasPrev}
                  onClick={() => setPage(page - 1)}
                >
                  Previous
                </Button>
                <Button
                  variant="outline"
                  disabled={!usersData?.meta?.hasNext}
                  onClick={() => setPage(page + 1)}
                >
                  Next
                </Button>
              </div>
            </div>
          </>
        )}
      </Card>

      {/* User Detail Drawer */}
      <Drawer open={showDetailDrawer} onClose={handleCloseDrawer} side="right">
        {isLoadingDetail ? (
          <div className="flex items-center justify-center py-12">
            <LoadingSpinner />
          </div>
        ) : userDetail ? (
          <div className="space-y-6">
            {/* User Profile */}
            <div>
              <h3 className="font-heading text-lg font-bold text-white mb-4">
                User Profile
              </h3>
              <div className="space-y-3">
                <div>
                  <p className="text-xs text-[#9CA3AF] uppercase tracking-wide">Username</p>
                  <p className="text-white font-medium">{userDetail.username}</p>
                </div>
                <div>
                  <p className="text-xs text-[#9CA3AF] uppercase tracking-wide">Email</p>
                  <p className="text-white font-medium">{userDetail.email}</p>
                </div>
                <div>
                  <p className="text-xs text-[#9CA3AF] uppercase tracking-wide">Role</p>
                  <p className="text-white font-medium">{userDetail.role}</p>
                </div>
                <div>
                  <p className="text-xs text-[#9CA3AF] uppercase tracking-wide">Status</p>
                  <div className="flex items-center gap-2 mt-1">
                    <span
                      className={`px-2 py-1 rounded-full text-xs font-semibold ${
                        userDetail.isBanned
                          ? 'bg-red-500/20 text-red-400'
                          : 'bg-green-500/20 text-green-400'
                      }`}
                    >
                      {userDetail.isBanned ? 'Banned' : 'Active'}
                    </span>
                    {userDetail.isBanned && userDetail.lockedUntil && (
                      <span className="text-xs text-[#9CA3AF]">
                        Until {new Date(userDetail.lockedUntil).toLocaleString()}
                      </span>
                    )}
                  </div>
                </div>
                <div>
                  <p className="text-xs text-[#9CA3AF] uppercase tracking-wide">Joined</p>
                  <p className="text-white font-medium">
                    {new Date(userDetail.createdAt).toLocaleString()}
                  </p>
                </div>
                <div>
                  <p className="text-xs text-[#9CA3AF] uppercase tracking-wide">Last Login</p>
                  <p className="text-white font-medium">
                    {userDetail.lastLoginAt
                      ? new Date(userDetail.lastLoginAt).toLocaleString()
                      : 'Never'}
                  </p>
                </div>
              </div>
            </div>

            {/* Characters */}
            {userDetail.characters && userDetail.characters.length > 0 && (
              <div>
                <h3 className="font-heading text-lg font-bold text-white mb-4">
                  Characters
                </h3>
                <div className="space-y-2">
                  {userDetail.characters.map((char) => (
                    <div
                      key={char.id}
                      className="bg-[#7C3AED]/10 border border-[#7C3AED]/20 rounded-lg p-3"
                    >
                      <p className="text-white font-medium">{char.name}</p>
                      <p className="text-xs text-[#9CA3AF]">
                        {char.class} - Level {char.level}
                      </p>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Recent Activity */}
            {userDetail.recentActivity && userDetail.recentActivity.length > 0 && (
              <div>
                <h3 className="font-heading text-lg font-bold text-white mb-4">
                  Recent Activity
                </h3>
                <div className="space-y-2 max-h-48 overflow-y-auto">
                  {userDetail.recentActivity.map((activity) => (
                    <div
                      key={activity.id}
                      className="bg-[#7C3AED]/10 border border-[#7C3AED]/20 rounded-lg p-3"
                    >
                      <p className="text-white font-medium text-sm">
                        {activity.actionType}
                      </p>
                      <p className="text-xs text-[#9CA3AF]">
                        {new Date(activity.createdAt).toLocaleString()}
                      </p>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Actions */}
            <div className="space-y-2 pt-4 border-t border-[#7C3AED]/20">
              <Button
                onClick={handleOpenRoleModal}
                className="w-full flex items-center justify-center gap-2 bg-[#7C3AED] hover:bg-[#7C3AED]/80"
              >
                <Shield className="w-4 h-4" />
                Change Role
              </Button>
              {!userDetail.isBanned ? (
                <Button
                  onClick={handleOpenBanModal}
                  className="w-full flex items-center justify-center gap-2 bg-red-600 hover:bg-red-700"
                >
                  <Ban className="w-4 h-4" />
                  Ban User
                </Button>
              ) : (
                <Button
                  onClick={() => unbanUserMutation.mutate()}
                  disabled={unbanUserMutation.isPending}
                  className="w-full flex items-center justify-center gap-2 bg-green-600 hover:bg-green-700"
                >
                  <CheckCircle className="w-4 h-4" />
                  {unbanUserMutation.isPending ? 'Unbanning...' : 'Unban User'}
                </Button>
              )}
            </div>
          </div>
        ) : null}
      </Drawer>

      {/* Ban User Modal */}
      <Modal open={showBanModal} onClose={() => setShowBanModal(false)}>
        <ModalHeader>
          <ModalTitle>Ban User</ModalTitle>
        </ModalHeader>
        <div className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-white mb-2">
              Reason for Ban
            </label>
            <Input
              placeholder="Enter ban reason..."
              value={banReason}
              onChange={(e) => setBanReason(e.target.value)}
              className="w-full"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-white mb-2">
              Duration (hours)
            </label>
            <div className="flex gap-2">
              <Input
                type="number"
                placeholder="Leave empty for permanent ban"
                value={banDuration ?? ''}
                onChange={(e) =>
                  setBanDuration(e.target.value ? parseInt(e.target.value, 10) : null)
                }
                className="flex-1"
              />
              <Button
                onClick={() => setBanDuration(24)}
                variant="outline"
                className="text-xs"
              >
                24h
              </Button>
              <Button
                onClick={() => setBanDuration(168)}
                variant="outline"
                className="text-xs"
              >
                7d
              </Button>
            </div>
          </div>
        </div>
        <ModalFooter>
          <Button
            variant="outline"
            onClick={() => setShowBanModal(false)}
          >
            Cancel
          </Button>
          <Button
            onClick={() => banUserMutation.mutate()}
            disabled={!banReason || banUserMutation.isPending}
            className="bg-red-600 hover:bg-red-700"
          >
            {banUserMutation.isPending ? 'Banning...' : 'Ban User'}
          </Button>
        </ModalFooter>
      </Modal>

      {/* Change Role Modal */}
      <Modal open={showRoleModal} onClose={() => setShowRoleModal(false)}>
        <ModalHeader>
          <ModalTitle>Change User Role</ModalTitle>
        </ModalHeader>
        <div className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-white mb-2">
              New Role
            </label>
            <Select
              value={newRole}
              onChange={(e) => setNewRole(e.target.value)}
              className="w-full"
            >
              <SelectOption value="">Select a role</SelectOption>
              <SelectOption value="USER">User</SelectOption>
              <SelectOption value="GM">Game Master</SelectOption>
              <SelectOption value="ADMIN">Admin</SelectOption>
            </Select>
          </div>
        </div>
        <ModalFooter>
          <Button
            variant="outline"
            onClick={() => setShowRoleModal(false)}
          >
            Cancel
          </Button>
          <Button
            onClick={() => changeRoleMutation.mutate()}
            disabled={!newRole || changeRoleMutation.isPending}
            className="bg-[#7C3AED] hover:bg-[#7C3AED]/80"
          >
            {changeRoleMutation.isPending ? 'Changing...' : 'Change Role'}
          </Button>
        </ModalFooter>
      </Modal>
    </div>
  );
}

'use client';

import { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { Card, Input, Button, Modal, ModalHeader, ModalTitle, ModalFooter, Drawer } from '@mmorpg/ui';
import { Search, Trash2, Ban, AlertCircle, CheckCircle, Clock } from 'lucide-react';
import { LoadingSpinner } from '@/components/loading-spinner';

interface FlaggedListing {
  id: string;
  sellerId: string;
  sellerName: string;
  itemName: string;
  itemCategory: string;
  itemRarity: string;
  price: string;
  listingType: string;
  status: string;
  createdAt: string;
}

export default function ModerationPage() {
  const [searchQuery, setSearchQuery] = useState('');
  const [page, setPage] = useState(1);
  const [selectedListingId, setSelectedListingId] = useState<string | null>(null);
  const [selectedSellerId, setSelectedSellerId] = useState<string | null>(null);
  const [showRemoveModal, setShowRemoveModal] = useState(false);
  const [showTradeBanModal, setShowTradeBanModal] = useState(false);
  const [removeReason, setRemoveReason] = useState('');
  const [tradeBanReason, setTradeBanReason] = useState('');
  const [tradeBanDuration, setTradeBanDuration] = useState<number | null>(null);
  const [actionError, setActionError] = useState<string | null>(null);
  const [actionSuccess, setActionSuccess] = useState<string | null>(null);

  const queryClient = useQueryClient();

  const { data: flaggedListingsData, isLoading } = useQuery({
    queryKey: ['admin', 'marketplace', 'flagged', page, searchQuery],
    queryFn: async () => {
      const params = new URLSearchParams({
        page: page.toString(),
        pageSize: '20',
        ...(searchQuery && { query: searchQuery }),
      });
      const response = await fetch(`/api/admin/marketplace/flagged?${params}`);
      if (!response.ok) throw new Error('Failed to fetch flagged listings');
      return response.json();
    },
  });

  const removeListingMutation = useMutation({
    mutationFn: async () => {
      if (!selectedListingId) throw new Error('No listing selected');
      const response = await fetch(
        `/api/admin/marketplace/listings/${selectedListingId}/remove`,
        {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ reason: removeReason }),
        }
      );
      if (!response.ok) throw new Error('Failed to remove listing');
      return response.json();
    },
    onSuccess: () => {
      setActionSuccess('Listing removed successfully');
      setShowRemoveModal(false);
      setRemoveReason('');
      setSelectedListingId(null);
      queryClient.invalidateQueries({ queryKey: ['admin', 'marketplace', 'flagged'] });
      setTimeout(() => setActionSuccess(null), 3000);
    },
    onError: (error) => {
      setActionError(error instanceof Error ? error.message : 'Failed to remove listing');
      setTimeout(() => setActionError(null), 3000);
    },
  });

  const tradeBanMutation = useMutation({
    mutationFn: async () => {
      if (!selectedSellerId) throw new Error('No seller selected');
      const response = await fetch(
        `/api/admin/marketplace/users/${selectedSellerId}/trade-ban`,
        {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            reason: tradeBanReason,
            durationHours: tradeBanDuration,
          }),
        }
      );
      if (!response.ok) throw new Error('Failed to issue trade ban');
      return response.json();
    },
    onSuccess: () => {
      setActionSuccess('Trade ban issued successfully');
      setShowTradeBanModal(false);
      setTradeBanReason('');
      setTradeBanDuration(null);
      setSelectedSellerId(null);
      queryClient.invalidateQueries({ queryKey: ['admin', 'marketplace', 'flagged'] });
      setTimeout(() => setActionSuccess(null), 3000);
    },
    onError: (error) => {
      setActionError(error instanceof Error ? error.message : 'Failed to issue trade ban');
      setTimeout(() => setActionError(null), 3000);
    },
  });

  const handleRemoveListing = (listingId: string) => {
    setSelectedListingId(listingId);
    setShowRemoveModal(true);
  };

  const handleTradeBan = (sellerId: string) => {
    setSelectedSellerId(sellerId);
    setShowTradeBanModal(true);
  };

  const getRarityColor = (rarity: string) => {
    const rarityMap: Record<string, string> = {
      COMMON: 'bg-gray-500/20 text-gray-400',
      UNCOMMON: 'bg-green-500/20 text-green-400',
      RARE: 'bg-blue-500/20 text-blue-400',
      EPIC: 'bg-purple-500/20 text-purple-400',
      LEGENDARY: 'bg-yellow-500/20 text-yellow-400',
      MYTHIC: 'bg-red-500/20 text-red-400',
    };
    return rarityMap[rarity] || 'bg-gray-500/20 text-gray-400';
  };

  return (
    <div className="p-6 space-y-6">
      {/* Header */}
      <div>
        <h1 className="font-heading text-3xl font-bold text-white mb-2">
          Marketplace Moderation
        </h1>
        <p className="text-[#9CA3AF]">
          Review and manage flagged marketplace listings and user trading activity.
        </p>
      </div>

      {/* Notifications */}
      {actionSuccess && (
        <div className="bg-green-500/20 border-2 border-green-500/50 rounded-lg p-4 flex items-center gap-3">
          <CheckCircle className="w-5 h-5 text-green-400" />
          <p className="text-green-400 text-sm">{actionSuccess}</p>
        </div>
      )}
      {actionError && (
        <div className="bg-red-500/20 border-2 border-red-500/50 rounded-lg p-4 flex items-center gap-3">
          <AlertCircle className="w-5 h-5 text-red-400" />
          <p className="text-red-400 text-sm">{actionError}</p>
        </div>
      )}

      {/* Search */}
      <Card className="bg-[#111111] border-2 border-[#7C3AED]/20 p-6">
        <div className="flex flex-col md:flex-row gap-4">
          <div className="flex-1 relative">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-5 h-5 text-[#9CA3AF]" />
            <Input
              placeholder="Search by item name or seller..."
              value={searchQuery}
              onChange={(e) => {
                setSearchQuery(e.target.value);
                setPage(1);
              }}
              className="pl-10"
            />
          </div>
        </div>
      </Card>

      {/* Flagged Listings Table */}
      <Card className="bg-[#111111] border-2 border-[#7C3AED]/20 p-6">
        {isLoading ? (
          <div className="flex items-center justify-center py-12">
            <LoadingSpinner />
          </div>
        ) : flaggedListingsData?.data?.length === 0 ? (
          <div className="text-center py-12">
            <AlertCircle className="w-12 h-12 text-[#9CA3AF] mx-auto mb-4 opacity-50" />
            <p className="text-[#9CA3AF]">No flagged listings to review</p>
          </div>
        ) : (
          <>
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="border-b border-[#7C3AED]/20">
                    <th className="text-left py-3 px-4 text-sm font-semibold text-[#9CA3AF]">
                      Item
                    </th>
                    <th className="text-left py-3 px-4 text-sm font-semibold text-[#9CA3AF]">
                      Seller
                    </th>
                    <th className="text-left py-3 px-4 text-sm font-semibold text-[#9CA3AF]">
                      Category
                    </th>
                    <th className="text-left py-3 px-4 text-sm font-semibold text-[#9CA3AF]">
                      Rarity
                    </th>
                    <th className="text-left py-3 px-4 text-sm font-semibold text-[#9CA3AF]">
                      Price
                    </th>
                    <th className="text-left py-3 px-4 text-sm font-semibold text-[#9CA3AF]">
                      Listed
                    </th>
                    <th className="text-right py-3 px-4 text-sm font-semibold text-[#9CA3AF]">
                      Actions
                    </th>
                  </tr>
                </thead>
                <tbody>
                  {flaggedListingsData?.data?.map((listing: FlaggedListing) => (
                    <tr
                      key={listing.id}
                      className="border-b border-[#7C3AED]/10 hover:bg-[#7C3AED]/5 transition-colors"
                    >
                      <td className="py-3 px-4 text-sm text-white font-medium">
                        {listing.itemName}
                      </td>
                      <td className="py-3 px-4 text-sm text-[#9CA3AF]">
                        {listing.sellerName}
                      </td>
                      <td className="py-3 px-4 text-sm text-[#9CA3AF]">
                        {listing.itemCategory}
                      </td>
                      <td className="py-3 px-4 text-sm">
                        <span
                          className={`px-2 py-1 rounded-full text-xs font-semibold ${getRarityColor(
                            listing.itemRarity
                          )}`}
                        >
                          {listing.itemRarity}
                        </span>
                      </td>
                      <td className="py-3 px-4 text-sm text-white font-medium">
                        {listing.price}
                      </td>
                      <td className="py-3 px-4 text-sm text-[#9CA3AF]">
                        {new Date(listing.createdAt).toLocaleDateString()}
                      </td>
                      <td className="py-3 px-4 text-right">
                        <div className="flex items-center justify-end gap-2">
                          <button
                            onClick={() => handleRemoveListing(listing.id)}
                            className="p-2 hover:bg-red-500/10 rounded-lg transition-colors"
                            title="Remove listing"
                          >
                            <Trash2 className="w-4 h-4 text-red-400" />
                          </button>
                          <button
                            onClick={() => handleTradeBan(listing.sellerId)}
                            className="p-2 hover:bg-orange-500/10 rounded-lg transition-colors"
                            title="Trade ban seller"
                          >
                            <Ban className="w-4 h-4 text-orange-400" />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            {/* Pagination */}
            <div className="mt-6 flex items-center justify-between">
              <p className="text-sm text-[#9CA3AF]">
                Page {flaggedListingsData?.meta?.page} of{' '}
                {flaggedListingsData?.meta?.totalPages} (
                {flaggedListingsData?.meta?.total} total listings)
              </p>
              <div className="flex gap-2">
                <Button
                  variant="outline"
                  disabled={!flaggedListingsData?.meta?.hasPrev}
                  onClick={() => setPage(page - 1)}
                >
                  Previous
                </Button>
                <Button
                  variant="outline"
                  disabled={!flaggedListingsData?.meta?.hasNext}
                  onClick={() => setPage(page + 1)}
                >
                  Next
                </Button>
              </div>
            </div>
          </>
        )}
      </Card>

      {/* Remove Listing Modal */}
      <Modal open={showRemoveModal} onClose={() => setShowRemoveModal(false)}>
        <ModalHeader>
          <ModalTitle>Remove Listing</ModalTitle>
        </ModalHeader>
        <div className="space-y-4">
          <p className="text-sm text-[#9CA3AF]">
            Are you sure you want to remove this listing? The seller will be notified.
          </p>
          <div>
            <label className="block text-sm font-medium text-white mb-2">
              Reason for Removal
            </label>
            <Input
              placeholder="Enter removal reason..."
              value={removeReason}
              onChange={(e) => setRemoveReason(e.target.value)}
              className="w-full"
            />
          </div>
        </div>
        <ModalFooter>
          <Button
            variant="outline"
            onClick={() => setShowRemoveModal(false)}
          >
            Cancel
          </Button>
          <Button
            onClick={() => removeListingMutation.mutate()}
            disabled={!removeReason || removeListingMutation.isPending}
            className="bg-red-600 hover:bg-red-700"
          >
            {removeListingMutation.isPending ? 'Removing...' : 'Remove Listing'}
          </Button>
        </ModalFooter>
      </Modal>

      {/* Trade Ban Modal */}
      <Modal open={showTradeBanModal} onClose={() => setShowTradeBanModal(false)}>
        <ModalHeader>
          <ModalTitle>Issue Trade Ban</ModalTitle>
        </ModalHeader>
        <div className="space-y-4">
          <p className="text-sm text-[#9CA3AF]">
            This will prevent the user from trading on the marketplace.
          </p>
          <div>
            <label className="block text-sm font-medium text-white mb-2">
              Reason for Trade Ban
            </label>
            <Input
              placeholder="Enter ban reason..."
              value={tradeBanReason}
              onChange={(e) => setTradeBanReason(e.target.value)}
              className="w-full"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-white mb-2">
              Duration (hours)
            </label>
            <div className="flex gap-2">
              <Input
                type="number"
                placeholder="Leave empty for permanent ban"
                value={tradeBanDuration ?? ''}
                onChange={(e) =>
                  setTradeBanDuration(e.target.value ? parseInt(e.target.value, 10) : null)
                }
                className="flex-1"
              />
              <Button
                onClick={() => setTradeBanDuration(24)}
                variant="outline"
                className="text-xs"
              >
                24h
              </Button>
              <Button
                onClick={() => setTradeBanDuration(168)}
                variant="outline"
                className="text-xs"
              >
                7d
              </Button>
            </div>
          </div>
        </div>
        <ModalFooter>
          <Button
            variant="outline"
            onClick={() => setShowTradeBanModal(false)}
          >
            Cancel
          </Button>
          <Button
            onClick={() => tradeBanMutation.mutate()}
            disabled={!tradeBanReason || tradeBanMutation.isPending}
            className="bg-orange-600 hover:bg-orange-700"
          >
            {tradeBanMutation.isPending ? 'Banning...' : 'Issue Trade Ban'}
          </Button>
        </ModalFooter>
      </Modal>
    </div>
  );
}

'use client';

import { Drawer } from '@mmorpg/ui';
import { CheckCircle, Ban } from 'lucide-react';
import { Button } from '@mmorpg/ui';
import { LoadingSpinner } from '@/components/loading-spinner';

interface UserDetailDrawerProps {
  open: boolean;
  onClose: () => void;
  userDetail: any;
  isLoading: boolean;
  onBanClick: () => void;
  onUnbanClick: () => void;
  onRoleClick: () => void;
  isBanning?: boolean;
  isUnbanning?: boolean;
}

export function UserDetailDrawer({
  open,
  onClose,
  userDetail,
  isLoading,
  onBanClick,
  onUnbanClick,
  onRoleClick,
  isBanning = false,
  isUnbanning = false,
}: UserDetailDrawerProps) {
  return (
    <Drawer open={open} onClose={onClose} side="right">
      {isLoading ? (
        <div className="flex items-center justify-center py-12">
          <LoadingSpinner />
        </div>
      ) : userDetail ? (
        <div className="space-y-6">
          {/* User Profile */}
          <div>
            <h3 className="font-heading text-lg font-bold text-white mb-4">
              User Profile
            </h3>
            <div className="space-y-3">
              <div>
                <p className="text-xs text-[#9CA3AF] uppercase tracking-wide">Username</p>
                <p className="text-white font-medium">{userDetail.username}</p>
              </div>
              <div>
                <p className="text-xs text-[#9CA3AF] uppercase tracking-wide">Email</p>
                <p className="text-white font-medium">{userDetail.email}</p>
              </div>
              <div>
                <p className="text-xs text-[#9CA3AF] uppercase tracking-wide">Role</p>
                <p className="text-white font-medium">{userDetail.role}</p>
              </div>
              <div>
                <p className="text-xs text-[#9CA3AF] uppercase tracking-wide">Status</p>
                <div className="flex items-center gap-2 mt-1">
                  <span
                    className={`px-2 py-1 rounded-full text-xs font-semibold ${
                      userDetail.isBanned
                        ? 'bg-red-500/20 text-red-400'
                        : 'bg-green-500/20 text-green-400'
                    }`}
                  >
                    {userDetail.isBanned ? 'Banned' : 'Active'}
                  </span>
                  {userDetail.isBanned && userDetail.lockedUntil && (
                    <span className="text-xs text-[#9CA3AF]">
                      Until {new Date(userDetail.lockedUntil).toLocaleString()}
                    </span>
                  )}
                </div>
              </div>
              <div>
                <p className="text-xs text-[#9CA3AF] uppercase tracking-wide">Joined</p>
                <p className="text-white font-medium">
                  {new Date(userDetail.createdAt).toLocaleString()}
                </p>
              </div>
              <div>
                <p className="text-xs text-[#9CA3AF] uppercase tracking-wide">Last Login</p>
                <p className="text-white font-medium">
                  {userDetail.lastLoginAt
                    ? new Date(userDetail.lastLoginAt).toLocaleString()
                    : 'Never'}
                </p>
              </div>
            </div>
          </div>

          {/* Characters */}
          {userDetail.characters && userDetail.characters.length > 0 && (
            <div>
              <h3 className="font-heading text-lg font-bold text-white mb-4">
                Characters
              </h3>
              <div className="space-y-2">
                {userDetail.characters.map((char: any) => (
                  <div
                    key={char.id}
                    className="bg-[#7C3AED]/10 border border-[#7C3AED]/20 rounded-lg p-3"
                  >
                    <p className="text-white font-medium">{char.name}</p>
                    <p className="text-xs text-[#9CA3AF]">
                      {char.class} - Level {char.level}
                    </p>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Recent Activity */}
          {userDetail.recentActivity && userDetail.recentActivity.length > 0 && (
            <div>
              <h3 className="font-heading text-lg font-bold text-white mb-4">
                Recent Activity
              </h3>
              <div className="space-y-2 max-h-48 overflow-y-auto">
                {userDetail.recentActivity.map((activity: any) => (
                  <div
                    key={activity.id}
                    className="bg-[#7C3AED]/10 border border-[#7C3AED]/20 rounded-lg p-3"
                  >
                    <p className="text-white font-medium text-sm">
                      {activity.actionType}
                    </p>
                    <p className="text-xs text-[#9CA3AF]">
                      {new Date(activity.createdAt).toLocaleString()}
                    </p>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Actions */}
          <div className="space-y-2 pt-4 border-t border-[#7C3AED]/20">
            <Button
              onClick={onRoleClick}
              className="w-full flex items-center justify-center gap-2 bg-[#7C3AED] hover:bg-[#7C3AED]/80"
            >
              <CheckCircle className="w-4 h-4" />
              Change Role
            </Button>
            {!userDetail.isBanned ? (
              <Button
                onClick={onBanClick}
                disabled={isBanning}
                className="w-full flex items-center justify-center gap-2 bg-red-600 hover:bg-red-700"
              >
                <Ban className="w-4 h-4" />
                {isBanning ? 'Banning...' : 'Ban User'}
              </Button>
            ) : (
              <Button
                onClick={onUnbanClick}
                disabled={isUnbanning}
                className="w-full flex items-center justify-center gap-2 bg-green-600 hover:bg-green-700"
              >
                <CheckCircle className="w-4 h-4" />
                {isUnbanning ? 'Unbanning...' : 'Unban User'}
              </Button>
            )}
          </div>
        </div>
      ) : null}
    </Drawer>
  );
}

import { useMutation, useQueryClient } from '@tanstack/react-query';
import { useState } from 'react';

interface AdminActionOptions {
  onSuccess?: (message: string) => void;
  onError?: (message: string) => void;
}

export function useAdminActions() {
  const queryClient = useQueryClient();
  const [actionError, setActionError] = useState<string | null>(null);
  const [actionSuccess, setActionSuccess] = useState<string | null>(null);

  const clearMessages = () => {
    setActionError(null);
    setActionSuccess(null);
  };

  const showError = (message: string) => {
    setActionError(message);
    setTimeout(() => setActionError(null), 3000);
  };

  const showSuccess = (message: string) => {
    setActionSuccess(message);
    setTimeout(() => setActionSuccess(null), 3000);
  };

  const banUserMutation = useMutation({
    mutationFn: async (params: {
      userId: string;
      reason: string;
      durationHours: number | null;
    }) => {
      const response = await fetch(`/api/admin/users/${params.userId}/ban`, {
        method: 'POST',
