import { useState } from 'react';
import { Modal, ModalHeader, ModalTitle, ModalFooter, Input, Button } from '@mmorpg/ui';

interface BanUserModalProps {
  open: boolean;
  onClose: () => void;
  onConfirm: (reason: string, durationHours: number | null) => void;
  isLoading?: boolean;
}

export function BanUserModal({
  open,
  onClose,
  onConfirm,
  isLoading = false,
}: BanUserModalProps) {
  const [reason, setReason] = useState('');
  const [duration, setDuration] = useState<number | null>(null);

  const handleConfirm = () => {
    onConfirm(reason, duration);
    setReason('');
    setDuration(null);
  };

  const handleClose = () => {
    setReason('');
    setDuration(null);
    onClose();
  };

  return (
    <Modal open={open} onClose={handleClose}>
      <ModalHeader>
        <ModalTitle>Ban User</ModalTitle>
      </ModalHeader>
      <div className="space-y-4">
        <div>
          <label className="block text-sm font-medium text-white mb-2">
            Reason for Ban
          </label>
          <Input
            placeholder="Enter ban reason..."
            value={reason}
            onChange={(e) => setReason(e.target.value)}
            className="w-full"
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-white mb-2">
            Duration (hours)
          </label>
          <div className="flex gap-2">
            <Input
              type="number"
              placeholder="Leave empty for permanent ban"
              value={duration ?? ''}
              onChange={(e) =>
                setDuration(e.target.value ? parseInt(e.target.value, 10) : null)
              }
              className="flex-1"
            />
            <Button
              onClick={() => setDuration(24)}
              variant="outline"
              className="text-xs"
            >
              24h
            </Button>
            <Button
              onClick={() => setDuration(168)}
              variant="outline"
              className="text-xs"
            >
              7d
            </Button>
          </div>
        </div>
      </div>
      <ModalFooter>
        <Button variant="outline" onClick={handleClose}>
          Cancel
        </Button>
        <Button
          onClick={handleConfirm}
          disabled={!reason || isLoading}
          className="bg-red-600 hover:bg-red-700"
        >
          {isLoading ? 'Banning...' : 'Ban User'}
        </Button>
      </ModalFooter>
    </Modal>
  );
}

